import base64
import hashlib
import json
import math
import re
from dataclasses import dataclass, field
from pathlib import Path
from typing import Any


# ── Multimodal content types ──────────────────────────────────────────────────
@dataclass
class ImageContent:
    image_b64: str         # base64-encoded image
    media_type: str = 'image/jpeg'  # image/jpeg, image/png, image/webp
    description: str = ''  # cached VLM description
    source_path: str = ''

    @classmethod
    def from_file(cls, path: str) -> 'ImageContent':
        data = Path(path).read_bytes()
        b64 = base64.b64encode(data).decode()
        ext = Path(path).suffix.lower()
        media_types = {'.jpg': 'image/jpeg', '.jpeg': 'image/jpeg',
                       '.png': 'image/png', '.webp': 'image/webp'}
        return cls(image_b64=b64, media_type=media_types.get(ext, 'image/jpeg'), source_path=path)

    def cache_key(self) -> str:
        return hashlib.sha256(self.image_b64[:100].encode()).hexdigest()[:12]

    def to_openai_message_part(self) -> dict:
        return {
            'type': 'image_url',
            'image_url': {
                'url': f'data:{self.media_type};base64,{self.image_b64}',
                'detail': 'high',
            }
        }


# ── VLM client ────────────────────────────────────────────────────────────────
class VLMClient:
    """
    Vision-Language Model client with description caching.
    In production, wrap the real OpenAI/Anthropic client.
    """

    def __init__(self, api_fn: Any):
        self._api = api_fn  # fn(messages) -> str
        self._cache: dict[str, str] = {}

    def describe_image(self, image: ImageContent, question: str = 'Describe this image in detail.') -> str:
        cache_key = f'{image.cache_key()}:{hashlib.md5(question.encode()).hexdigest()[:8]}'
        if cache_key in self._cache:
            return self._cache[cache_key]

        messages = [{
            'role': 'user',
            'content': [
                image.to_openai_message_part(),
                {'type': 'text', 'text': question},
            ]
        }]
        description = self._api(messages)
        self._cache[cache_key] = description
        return description

    def answer_about_image(self, image: ImageContent, question: str) -> str:
        return self.describe_image(image, question)

    def extract_structured(self, image: ImageContent, schema: dict) -> dict:
        schema_str = json.dumps(schema, indent=2)
        question = f'Extract information from this image as JSON matching this schema:\n{schema_str}\n\nOutput only valid JSON:'
        raw = self.describe_image(image, question)
        try:
            return json.loads(raw)
        except json.JSONDecodeError:
            # Attempt to extract JSON from markdown code block
            match = re.search(r'```(?:json)?\s*([\s\S]*?)```', raw)
            if match:
                return json.loads(match.group(1))
            return {}


# ── CLIP-style image embedding (simplified) ───────────────────────────────────
class CLIPEmbedder:
    """
    Simplified CLIP-style embedding using VLM descriptions + text embeddings.
    Production: use actual CLIP model (openai/clip-vit-large-patch14).
    """

    def __init__(self, vlm: VLMClient):
        self._vlm = vlm
        self._text_embed_cache: dict[str, list[float]] = {}

    def embed_image(self, image: ImageContent) -> list[float]:
        """Get image embedding via VLM description → text embedding."""
        if not image.description:
            image.description = self._vlm.describe_image(image)
        return self._embed_text(image.description)

    def embed_text(self, text: str) -> list[float]:
        return self._embed_text(text)

    def _embed_text(self, text: str) -> list[float]:
        """BoW embedding proxy."""
        if text in self._text_embed_cache:
            return self._text_embed_cache[text]
        tokens = re.findall(r'\w+', text.lower())
        vocab = sorted(set(tokens))
        vec = [tokens.count(w) for w in vocab]
        norm = math.sqrt(sum(x ** 2 for x in vec)) or 1.0
        embedding = [x / norm for x in vec]
        # Pad/trim to fixed dim 64 for simplicity
        while len(embedding) < 64:
            embedding.append(0.0)
        result = embedding[:64]
        self._text_embed_cache[text] = result
        return result

    def text_to_image_similarity(self, query: str, image: ImageContent) -> float:
        q_emb = self.embed_text(query)
        i_emb = self.embed_image(image)
        # Cosine similarity
        dot = sum(a * b for a, b in zip(q_emb[:len(i_emb)], i_emb))
        na = math.sqrt(sum(x ** 2 for x in q_emb)) or 1e-9
        nb = math.sqrt(sum(x ** 2 for x in i_emb)) or 1e-9
        return dot / (na * nb)


# ── Audio transcription pipeline ──────────────────────────────────────────────
@dataclass
class TranscriptSegment:
    start_s: float
    end_s: float
    text: str
    speaker: str = 'unknown'

@dataclass
class Transcript:
    segments: list[TranscriptSegment]
    language: str = 'en'
    duration_s: float = 0.0

    def full_text(self) -> str:
        return ' '.join(s.text for s in self.segments)

    def text_by_speaker(self) -> dict[str, str]:
        result: dict[str, list[str]] = {}
        for seg in self.segments:
            result.setdefault(seg.speaker, []).append(seg.text)
        return {speaker: ' '.join(texts) for speaker, texts in result.items()}


class AudioPipeline:
    """
    Simulates Whisper transcription + speaker diarisation.
    Production: whisper.transcribe(audio_path) + pyannote.audio for diarisation.
    """

    def __init__(self, whisper_fn: Any, diarisation_fn: Any | None = None):
        self._whisper = whisper_fn
        self._diarise = diarisation_fn

    def transcribe(self, audio_path: str, chunk_s: float = 30.0) -> Transcript:
        raw_segments = self._whisper(audio_path)  # returns list[dict] with start/end/text
        segments = [
            TranscriptSegment(
                start_s=seg['start'],
                end_s=seg['end'],
                text=seg['text'].strip(),
            )
            for seg in raw_segments
        ]
        # Apply diarisation if available
        if self._diarise:
            speaker_map = self._diarise(audio_path)  # {(start, end): speaker_id}
            for seg in segments:
                seg.speaker = self._assign_speaker(seg, speaker_map)

        duration = max((seg.end_s for seg in segments), default=0.0)
        return Transcript(segments=segments, duration_s=duration)

    @staticmethod
    def _assign_speaker(seg: TranscriptSegment, speaker_map: dict) -> str:
        mid = (seg.start_s + seg.end_s) / 2
        for (start, end), speaker in speaker_map.items():
            if start <= mid <= end:
                return speaker
        return 'unknown'


# ── Multimodal RAG pipeline ───────────────────────────────────────────────────
@dataclass
class MultimodalDocument:
    doc_id: str
    text: str
    images: list[ImageContent] = field(default_factory=list)
    metadata: dict = field(default_factory=dict)


class MultimodalRAG:
    """
    Retrieves from both text and image corpora, fuses with RRF, generates with VLM.
    """

    def __init__(self, vlm: VLMClient, clip: CLIPEmbedder):
        self._vlm = vlm
        self._clip = clip
        self._text_docs: list[MultimodalDocument] = []
        self._images: list[tuple[ImageContent, str]] = []  # (image, doc_id)

    def index(self, docs: list[MultimodalDocument]) -> None:
        for doc in docs:
            self._text_docs.append(doc)
            for img in doc.images:
                self._images.append((img, doc.doc_id))

    def _text_search(self, query: str, top_k: int) -> list[tuple[float, MultimodalDocument]]:
        scored = []
        q_tokens = set(re.findall(r'\w+', query.lower()))
        for doc in self._text_docs:
            d_tokens = set(re.findall(r'\w+', doc.text.lower()))
            overlap = len(q_tokens & d_tokens) / len(q_tokens | d_tokens) if q_tokens | d_tokens else 0
            scored.append((overlap, doc))
        return sorted(scored, key=lambda x: -x[0])[:top_k]

    def _image_search(self, query: str, top_k: int) -> list[tuple[float, ImageContent, str]]:
        scored = [
            (self._clip.text_to_image_similarity(query, img), img, doc_id)
            for img, doc_id in self._images
        ]
        return sorted(scored, key=lambda x: -x[0])[:top_k]

    def query(self, question: str, top_k: int = 3) -> dict:
        # Retrieve text
        text_results = self._text_search(question, top_k)
        context_texts = [doc.text[:500] for _, doc in text_results]

        # Retrieve images
        image_results = self._image_search(question, top_k)
        context_images = [img for _, img, _ in image_results]

        # Build multimodal context for VLM
        image_descriptions = [
            f'[Image {i+1}]: {img.description or self._vlm.describe_image(img)}'
            for i, img in enumerate(context_images)
        ]

        full_context = '\n\n'.join(
            [f'Text context:\n' + '\n'.join(context_texts)] +
            image_descriptions
        )

        # Generate answer with VLM
        messages = [{
            'role': 'user',
            'content': [
                *[img.to_openai_message_part() for img in context_images[:2]],  # max 2 images
                {'type': 'text', 'text': f'Context:\n{full_context}\n\nQuestion: {question}\n\nAnswer:'},
            ]
        }]

        answer = self._vlm._api(messages)
        return {
            'answer': answer,
            'text_sources': [doc.doc_id for _, doc in text_results],
            'image_sources': [(doc_id, img.source_path) for _, img, doc_id in image_results],
        }


# ── Demo ──────────────────────────────────────────────────────────────────────
if __name__ == '__main__':
    def mock_vlm_api(messages) -> str:
        # Extract text content for mock response
        for msg in messages:
            if isinstance(msg.get('content'), list):
                for part in msg['content']:
                    if part.get('type') == 'text':
                        return f'[Mock VLM response to: {part["text"][:50]}...]'
        return '[Mock VLM response]'

    vlm = VLMClient(mock_vlm_api)

    # Simulate image with description
    img = ImageContent(image_b64='abc123', description='A bar chart showing revenue growth from 2020 to 2024')
    clip = CLIPEmbedder(vlm)

    # Text-to-image similarity
    sim = clip.text_to_image_similarity('quarterly revenue chart', img)
    print(f'Text-image similarity: {sim:.3f}')

    # Multimodal RAG
    docs = [
        MultimodalDocument(
            doc_id='report_q4',
            text='Q4 2024 revenue reached $50M, a 30% increase year-over-year. Gross margin improved to 72%.',
            images=[img],
            metadata={'year': 2024, 'quarter': 'Q4'},
        ),
        MultimodalDocument(
            doc_id='report_q3',
            text='Q3 2024 revenue was $38M. Operating expenses increased by 15% due to headcount growth.',
            images=[],
            metadata={'year': 2024, 'quarter': 'Q3'},
        ),
    ]

    rag = MultimodalRAG(vlm, clip)
    rag.index(docs)
    result = rag.query('What was the revenue growth?')
    print('\nMultimodal RAG result:')
    print(f'Answer: {result["answer"]}')
    print(f'Text sources: {result["text_sources"]}')
    print(f'Image sources: {result["image_sources"]}')

    # Audio pipeline demo
    def mock_whisper(path: str) -> list[dict]:
        return [
            {'start': 0.0, 'end': 4.5, 'text': 'The Q4 revenue exceeded our targets.'},
            {'start': 4.5, 'end': 9.0, 'text': 'Gross margins improved to 72 percent.'},
        ]

    audio = AudioPipeline(mock_whisper)
    transcript = audio.transcribe('meeting.mp3')
    print(f'\nTranscript: {transcript.full_text()}')
    print(f'Duration: {transcript.duration_s}s, Segments: {len(transcript.segments)}')
